import itertools

class Brick:
    def __init__(self, id):
        self.id = id
        self.connections = []

    def connect(self, brick):
        self.connections.append(brick)

class BrickCombination:
    def __init__(self, bricks):
        self.bricks = bricks
        self.connections = []

    def add_connection(self, brick1, brick2):
        self.connections.append((brick1, brick2))

    def is_trivial(self):
        # A combination is trivial if all bricks are connected in a straight line
        if len(self.bricks) == 1:
            return True
        for brick in self.bricks:
            if len(brick.connections) > 2:
                return False
        return True

    def get_class_rating(self):
        # A combination is complicated if it has more than 2 branches
        branches = 0
        for brick in self.bricks:
            if len(brick.connections) > 2:
                branches += 1
        if branches > 2:
            return "complicated"
        elif self.is_trivial():
            return "trivial"
        else:
            return "moderate"

def generate_combinations(bricks):
    combinations = []
    for r in range(1, len(bricks) + 1):
        for combination in itertools.combinations(bricks, r):
            combination_bricks = [Brick(i) for i in range(len(combination))]
            for i in range(len(combination_bricks)):
                for j in range(i + 1, len(combination_bricks)):
                    combination_bricks[i].connect(combination_bricks[j])
                    combination_bricks[j].connect(combination_bricks[i])
            combination_obj = BrickCombination(combination_bricks)
            for i in range(len(combination_bricks)):
                for j in range(i + 1, len(combination_bricks)):
                    combination_obj.add_connection(combination_bricks[i], combination_bricks[j])
            combinations.append(combination_obj)
    return combinations

def count_combinations(bricks):
    combinations = generate_combinations(bricks)
    return len(combinations)

def verify_lego_claim():
    bricks = [1, 2, 3, 4, 5, 6]
    combinations = generate_combinations(bricks)
    trivial_combinations = [combination for combination in combinations if combination.is_trivial()]
    complicated_combinations = [combination for combination in combinations if combination.get_class_rating() == "complicated"]
    print("Total combinations:", len(combinations))
    print("Trivial combinations:", len(trivial_combinations))
    print("Complicated combinations:", len(complicated_combinations))

verify_lego_claim()

