import itertools

class Brick:
    def __init__(self, id):
        self.id = id
        self.connections = []

    def connect(self, brick):
        self.connections.append(brick)
        brick.connections.append(self)

def generate_combinations(bricks):
    combinations = []
    for p in itertools.permutations(bricks):
        combination = []
        for i in range(len(p) - 1):
            combination.append((p[i], p[i + 1]))
        combinations.append(combination)
    return combinations

def calculate_combinations(bricks):
    combinations = generate_combinations(bricks)
    valid_combinations = []
    for combination in combinations:
        graph = {}
        for brick in bricks:
            graph[brick.id] = []
        for connection in combination:
            graph[connection[0].id].append(connection[1].id)
            graph[connection[1].id].append(connection[0].id)
        if is_connected(graph):
            valid_combinations.append(combination)
    return valid_combinations

def is_connected(graph):
    visited = set()
    stack = [next(iter(graph))]
    while stack:
        node = stack.pop()
        if node not in visited:
            visited.add(node)
            stack.extend(neighbor for neighbor in graph[node] if neighbor not in visited)
    return len(visited) == len(graph)

def classify_combination(combination):
    complexity = 0
    for brick in combination:
        complexity += len(brick.connections)
    if complexity <= 10:
        return 'trivial'
    elif complexity <= 20:
        return 'moderate'
    else:
        return 'complicated'

