    bricks = [Brick(i) for i in range(6)]
    combinations = calculate_combinations(bricks)
    print(f'Total combinations: {len(combinations)}')
    trivial_combinations = [combination for combination in combinations if classify_combination(combination) == 'trivial']
    moderate_combinations = [combination for combination in combinations if classify_combination(combination) == 'moderate']
    complicated_combinations = [combination for combination in combinations if classify_combination(combination) == 'complicated']
    print(f'Trivial combinations: {len(trivial_combinations)}')
    print(f'Moderate combinations: {len(moderate_combinations)}')
    print(f'Complicated combinations: {len(complicated_combinations)}')

if __name__ == '__main__':
    main()

