def calculate_frequency(message):
    frequency = {}
    for symbol in message:
        if symbol not in frequency:
            frequency[symbol] = 1
        else:
            frequency[symbol] += 1
    return frequency

def generate_huffman_codes(frequency):
    import heapq
    heap = [[weight, [symbol, ""]] for symbol, weight in frequency.items()]
    heapq.heapify(heap)
    while len(heap) > 1:
        lo = heapq.heappop(heap)
        hi = heapq.heappop(heap)
        for pair in lo[1:]:
            pair[1] = '0' + pair[1]
        for pair in hi[1:]:
            pair[1] = '1' + pair[1]
        heapq.heappush(heap, [lo[0] + hi[0]] + lo[1:] + hi[1:])
    return sorted(heapq.heappop(heap)[1:], key=lambda p: (len(p[-1]), p))

def huffman_encoding(message):
    frequency = calculate_frequency(message)
    huffman_codes = generate_huffman_codes(frequency)
    huffman_dict = {}
    for p in huffman_codes:
        huffman_dict[p[0]] = p[1]
    encoded_message = ''
    for char in message:
        encoded_message += huffman_dict[char]
    return encoded_message, huffman_dict

def huffman_decoding(encoded_message, huffman_dict):
    reverse_dict = {}
    for key, value in huffman_dict.items():
        reverse_dict[value] = key
    decoded_message = ''
    temp = ''
    for bit in encoded_message:
        temp += bit
        if temp in reverse_dict:
            decoded_message += reverse_dict[temp]
            temp = ''
    return decoded_message

